scripts.content:
extends Control

signal text_finished
signal choice_selected(index: int, choice_id: String)
signal dialogue_requested_next

@export var characters_per_second: float = {{characters_per_second}}

@onready var _speaker_label: Label = %SpeakerLabel
@onready var _dialogue_label: RichTextLabel = %DialogueLabel
@onready var _portrait: TextureRect = %Portrait
@onready var _choices_container: VBoxContainer = %ChoicesContainer
@onready var _continue_indicator: Control = %ContinueIndicator
@onready var _typewriter: Timer = $TypewriterTimer

var _full_text: String = ""
var _visible_chars: int = 0
var _is_typing: bool = false
var _choices_active: bool = false
var _can_continue: bool = false

func _ready():
	hide()
	_typewriter.timeout.connect(_on_typewriter_tick)
	_clear_choices()

func start_dialogue(entry: Dictionary) -> void:
	"""Show a dialogue line with speaker, text, and optional portrait.
	entry = { speaker: String, text: String, portrait: Texture2D|null, sfx: AudioStream|null }
	"""
	show()
	_clear_choices()
	_continue_indicator.hide()
	_can_continue = false

	_speaker_label.text = entry.get("speaker", "")
	_full_text = entry.get("text", "")

	# Portrait
	var portrait: Texture2D = entry.get("portrait")
	if portrait:
		_portrait.texture = portrait
		_portrait.show()
	else:
		_portrait.hide()

	# Start typewriter
	_visible_chars = 0
	_dialogue_label.text = _full_text
	_dialogue_label.visible_characters = 0
	_is_typing = true
	_typewriter.start(1.0 / characters_per_second)

func show_choices(choices: Array[Dictionary]) -> void:
	"""Display choice buttons.
	choices = [{ id: String, text: String, enabled: bool }, ...]
	"""
	_clear_choices()
	_choices_active = true

	for i in range(choices.size()):
		var choice := choices[i]
		var btn := Button.new()
		btn.text = "%d. %s" % [i + 1, choice.get("text", "")]
		btn.flat = false
		btn.add_theme_font_size_override("font_size", {{choice_font_size}})
		btn.disabled = not choice.get("enabled", true)
		btn.size_flags_horizontal = Control.SIZE_FILL
		btn.custom_minimum_size = Vector2(0, 44)

		var idx := i
		var choice_id: String = choice.get("id", "")
		btn.pressed.connect(func(): _on_choice_pressed(idx, choice_id))

		_choices_container.add_child(btn)

func skip_typewriter() -> void:
	"""Instantly reveal all text."""
	if _is_typing:
		_typewriter.stop()
		_dialogue_label.visible_characters = -1
		_is_typing = false
		_on_text_finished()

func is_typing() -> bool:
	return _is_typing

func is_showing_choices() -> bool:
	return _choices_active

func clear() -> void:
	hide()
	_speaker_label.text = ""
	_dialogue_label.text = ""
	_portrait.texture = null
	_clear_choices()
	_continue_indicator.hide()
	_is_typing = false
	_typewriter.stop()

func _on_typewriter_tick() -> void:
	_visible_chars += 1
	_dialogue_label.visible_characters = _visible_chars

	# Check if we should pause for punctuation
	var shown := _full_text.substr(0, min(_visible_chars, _full_text.length()))
	if shown.ends_with(",") or shown.ends_with(";"):
		_typewriter.wait_time = 0.2
	elif shown.ends_with(".") or shown.ends_with("!") or shown.ends_with("?"):
		_typewriter.wait_time = 0.4
	elif shown.ends_with("…"):
		_typewriter.wait_time = 0.6
	else:
		_typewriter.wait_time = 1.0 / characters_per_second

	if _visible_chars >= _full_text.length():
		_typewriter.stop()
		_is_typing = false
		_on_text_finished()

func _on_text_finished() -> void:
	_dialogue_label.visible_characters = -1
	_can_continue = true
	_continue_indicator.show()
	text_finished.emit()

func _on_choice_pressed(index: int, choice_id: String) -> void:
	choice_selected.emit(index, choice_id)
	_clear_choices()

func _clear_choices() -> void:
	for child in _choices_container.get_children():
		child.queue_free()
	_choices_active = false

func _input(event: InputEvent) -> void:
	if not visible:
		return

	if event.is_action_pressed("ui_accept") or event.is_action_pressed("interact"):
		if _is_typing:
			skip_typewriter()
			get_viewport().set_input_as_handled()
		elif _can_continue and not _choices_active:
			dialogue_requested_next.emit()
			get_viewport().set_input_as_handled()
